u(t)=\varepsilon(t) = 
\begin{cases} 
    1 &amp;amp;  t \gt 0 \\
    \text{undifined} &amp;amp;  t = 0 \\
    0 &amp;amp;  t \lt 0 
\end{cases}
\end{aligned}
